// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.hypergraph;

/**
 * DPhyp connected-subgraph / connected-complement enumeration (Moerkotte &amp; Neumann, "Dynamic Programming Strikes
 * Back", SIGMOD 2008; the same algorithm drives MySQL 8's hypergraph join optimizer).
 * <p>
 * For a join hypergraph this emits, exactly once, every pair (S, C) of disjoint connected node sets that are joined by
 * some hyperedge (one edge side fully inside S, the other fully inside C). Pairs are emitted in an order compatible
 * with dynamic programming: whenever a pair is emitted, every connected set that equals S, equals C, or was needed to
 * assemble either of them has already been announced through {@link Receiver#foundSingleNode(int)} or an earlier pair.
 * Cartesian products are never proposed: a disconnected node set is simply never assembled.
 * <p>
 * The receiver's {@link Receiver#hasSeen(long)} doubles as the connectivity oracle, exactly as in MySQL: a node set is
 * connected if and only if the receiver obtained a plan for it (a single node, or some emitted pair whose union it is).
 * This works because of the emission order guarantee above.
 */
public final class SubgraphEnumerator {

	/**
	 * Callbacks for the dynamic-programming layer. Both {@code found*} methods return {@code true} to abort the whole
	 * enumeration (e.g. a search budget was exhausted).
	 */
	public interface Receiver {

		/** True when a plan for exactly this node set exists; used by the enumerator as its connectivity test. */
		boolean hasSeen(long nodeSet);

		boolean foundSingleNode(int nodeIdx);

		/**
		 * A connected subgraph {@code left} and connected complement {@code right} joinable via the undirected edge
		 * {@code edgeIdx}. When several edges connect the pair, one representative is reported; the receiver is
		 * responsible for accounting for every join predicate that becomes applicable at this cut.
		 */
		boolean foundSubgraphPair(long left, long right, int edgeIdx);
	}

	private SubgraphEnumerator() {
	}

	/**
	 * Runs the enumeration over the whole graph. Returns {@code true} when a receiver callback aborted it.
	 */
	public static boolean enumerateConnectedPartitions(Hypergraph graph, Receiver receiver) {
		int nodeCount = graph.nodeCount();
		for (int seed = nodeCount - 1; seed >= 0; seed--) {
			if (receiver.foundSingleNode(seed)) {
				return true;
			}
			long seedSet = NodeSets.bit(seed);
			if (emitCsg(graph, receiver, seedSet)) {
				return true;
			}
			if (enumerateCsgRec(graph, receiver, seedSet, NodeSets.nodesBelowInclusive(seed))) {
				return true;
			}
		}
		return false;
	}

	/**
	 * The neighborhood N(S, X): nodes we may grow S with, ignoring the forbidden set X. For every directed arc whose
	 * near side lies fully inside S and whose far side avoids S, X and the neighborhood collected so far, the
	 * lowest-index node of the far side joins the neighborhood as the hypernode's representative. Simple arcs are
	 * pre-aggregated per node. Taking only a representative keeps subset enumeration over the neighborhood small; the
	 * rest of a hypernode is reached by growing through it in later recursion steps.
	 */
	private static long neighborhood(Hypergraph graph, long subgraph, long forbidden) {
		long blocked = subgraph | forbidden;
		long result = 0;
		for (long rest = subgraph; rest != 0; rest &= rest - 1L) {
			Hypergraph.Node node = graph.node(Long.numberOfTrailingZeros(rest));
			result |= node.simpleNeighborhood & ~blocked;
			for (int i = 0; i < node.complexArcs.size(); i++) {
				Hypergraph.Hyperedge arc = graph.arc(node.complexArcs.get(i));
				if (NodeSets.isSubset(arc.left(), subgraph)
						&& !NodeSets.overlaps(arc.right(), blocked | result)) {
					result |= NodeSets.lowestBit(arc.right());
				}
			}
		}
		return result;
	}

	/**
	 * Emits all csg-cmp pairs whose connected subgraph is exactly {@code subgraph}: seeds every complement from the
	 * neighborhood in descending node order (so each complement is enumerated from its lowest-index node exactly once),
	 * then grows each complement recursively.
	 */
	private static boolean emitCsg(Hypergraph graph, Receiver receiver, long subgraph) {
		long forbidden = subgraph | NodeSets.nodesBelowInclusive(NodeSets.lowestIndex(subgraph));
		long neighborhood = neighborhood(graph, subgraph, forbidden);
		for (long rest = neighborhood; rest != 0;) {
			int nodeIdx = NodeSets.highestIndex(rest);
			rest &= ~NodeSets.bit(nodeIdx);
			long complement = NodeSets.bit(nodeIdx);
			int edge = findConnectingEdge(graph, subgraph, complement);
			if (edge >= 0 && receiver.foundSubgraphPair(subgraph, complement, edge)) {
				return true;
			}
			long complementForbidden = forbidden | (neighborhood & NodeSets.nodesBelowInclusive(nodeIdx));
			if (enumerateCmpRec(graph, receiver, subgraph, complement, complementForbidden)) {
				return true;
			}
		}
		return false;
	}

	/** Grows the connected subgraph by every subset of its neighborhood, emitting pairs for each connected result. */
	private static boolean enumerateCsgRec(Hypergraph graph, Receiver receiver, long subgraph, long forbidden) {
		long neighborhood = neighborhood(graph, subgraph, forbidden);
		if (neighborhood == 0) {
			return false;
		}
		for (long sub = NodeSets.nextSubsetOf(0, neighborhood); sub != 0; sub = NodeSets.nextSubsetOf(sub,
				neighborhood)) {
			long grown = subgraph | sub;
			if (receiver.hasSeen(grown) && emitCsg(graph, receiver, grown)) {
				return true;
			}
		}
		for (long sub = NodeSets.nextSubsetOf(0, neighborhood); sub != 0; sub = NodeSets.nextSubsetOf(sub,
				neighborhood)) {
			if (enumerateCsgRec(graph, receiver, subgraph | sub, forbidden | neighborhood)) {
				return true;
			}
		}
		return false;
	}

	/** Grows the complement by every subset of its neighborhood, emitting a pair whenever the result is connected. */
	private static boolean enumerateCmpRec(Hypergraph graph, Receiver receiver, long subgraph, long complement,
			long forbidden) {
		long neighborhood = neighborhood(graph, complement, forbidden);
		if (neighborhood == 0) {
			return false;
		}
		for (long sub = NodeSets.nextSubsetOf(0, neighborhood); sub != 0; sub = NodeSets.nextSubsetOf(sub,
				neighborhood)) {
			long grown = complement | sub;
			if (receiver.hasSeen(grown)) {
				int edge = findConnectingEdge(graph, subgraph, grown);
				if (edge >= 0 && receiver.foundSubgraphPair(subgraph, grown, edge)) {
					return true;
				}
			}
		}
		for (long sub = NodeSets.nextSubsetOf(0, neighborhood); sub != 0; sub = NodeSets.nextSubsetOf(sub,
				neighborhood)) {
			if (enumerateCmpRec(graph, receiver, subgraph, complement | sub, forbidden | neighborhood)) {
				return true;
			}
		}
		return false;
	}

	/**
	 * An undirected edge with one side fully inside {@code a} and the other fully inside {@code b}, or -1. Used both to
	 * gate emission and to hand the receiver a representative join edge.
	 */
	static int findConnectingEdge(Hypergraph graph, long a, long b) {
		int edgeCount = graph.edgeCount();
		for (int e = 0; e < edgeCount; e++) {
			long left = graph.edgeLeft(e);
			long right = graph.edgeRight(e);
			if ((NodeSets.isSubset(left, a) && NodeSets.isSubset(right, b))
					|| (NodeSets.isSubset(left, b) && NodeSets.isSubset(right, a))) {
				return e;
			}
		}
		return -1;
	}
}
